Here's a comprehensive MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var client = new HttpClient(new FakeHandler(handler));
        return new DataFetcher(client);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        var fetcher = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var fetcher = CreateFetcher((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        });

        await Assert.ThrowsExactlyAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SlowResponse_CompletesWithinTimeout()
    {
        var fetcher = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(100, ct); // simulate latency
            return new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("delayed")
            };
        });

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("delayed", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_StopsEarly()
    {
        using var cts = new CancellationTokenSource();

        var fetcher = CreateFetcher(async (_, ct) =>
        {
            cts.Cancel(); // cancel while "in flight"
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });

        await Assert.ThrowsExactlyAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_PassesUrlToHandler()
    {
        Uri? capturedUri = null;
        var fetcher = CreateFetcher((req, _) =>
        {
            capturedUri = req.RequestUri;
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("")
            });
        });

        await fetcher.FetchAsync("https://example.com/api/data");

        Assert.AreEqual(new Uri("https://example.com/api/data"), capturedUri);
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> onSend)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => onSend(request, cancellationToken);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource` and assert `OperationCanceledException` |
| **Timeout** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` for cooperative cancellation |
| **Mid-flight cancel** | Cancel inside the handler to simulate abort during network I/O |
| **No mocking library** | A small `FakeHandler` overrides `SendAsync` directly — HttpClient delegates to it |

The critical detail: always pass `TestContext.CancellationToken` to your async calls in timeout tests. Without it, `[Timeout]` can't cooperatively cancel the work and the test hangs until the hard timeout kills it.
